CREATE VIEW `ads_grant_log_medal_item_log_view` (`product_id` COMMENT "产品id", `id` COMMENT "自增id", `user_id` COMMENT "用户id", `medal_num` COMMENT "勋章数量", `op_type` COMMENT "1：发放 2：消耗 3：过期", `source` COMMENT "来源", `send_num` COMMENT "发放数量", `source_key` COMMENT "来源key", `send_time` COMMENT "发放时间", `expire_time` COMMENT "过期时间", `create_time` COMMENT "创建时间", `app_id` COMMENT "应用程序id")
